// Map and validate form fields
const formData = $input.first().json.body;

const fieldMap = {
  'company_name': 'company_name',
  'company': 'company_name',
  'contact_email': 'contact_email',
  'email': 'contact_email',
  'project_title': 'project_title',
  'title': 'project_title',
  'project_description': 'description',
  'description': 'description',
  'development_stage': 'dev_stage',
  'budget_range': 'budget',
  'timeline': 'timeline',
  'technical_requirements': 'tech_requirements',
  'file_uploads': 'files'
};

const requiredFields = ['company_name', 'contact_email', 'project_title', 'description', 'dev_stage'];

const mapped = {};
const errors = [];

for (const [key, value] of Object.entries(formData)) {
  const cleanKey = key.trim().toLowerCase().replace(/[\s-]/g, '_');
  const colId = fieldMap[cleanKey] || cleanKey;
  if (value && String(value).trim()) {
    mapped[colId] = String(value).trim();
  }
}

for (const field of requiredFields) {
  if (!mapped[field]) {
    errors.push(`Missing required field: ${field}`);
  }
}

mapped.submitted_at = new Date().toISOString();
mapped.review_status = 'New';

return [{
  json: {
    valid: errors.length === 0,
    errors,
    mapped_data: mapped
  }
}];

// Log validation errors
const errors = $input.first().json.errors;
const formData = $input.first().json.mapped_data || {};

console.log('Validation failed:', JSON.stringify(errors));
console.log('Submitted data:', JSON.stringify(formData));

return [{
  json: {
    status: 'validation_failed',
    errors: errors,
    timestamp: new Date().toISOString(),
    contact_email: formData.contact_email || 'unknown'
  }
}];
